mapper.select:
SELECT sn.id, sn.notice_title, sn.notice_type, sn.data_status, sn.notice_start_time, sn.notice_end_time, sn.notice_top, sn.create_by, sn.create_time, su.username AS creator_username, su.nickname AS creator_nickname FROM sys_notice sn INNER JOIN sys_user su ON sn.create_by = su.id WHERE sn.enabled = '1'
AND sn.create_by IN (${req.userIdColl})
AND sn.notice_title LIKE CONCAT(#{req.noticeTitle},'%')
AND sn.notice_type = #{req.noticeType}
AND sn.data_status = #{req.dataStatus}
AND sn.notice_scope = #{req.noticeScope}
AND sn.notice_top = #{req.noticeTop}
AND (su.username LIKE CONCAT(#{req.creator},'%') OR su.nickname LIKE CONCAT(#{req.creator},'%'))
ORDER BY sn.notice_top DESC, sn.id DESC
